import { marked } from "marked";
import posts from "../../data/posts.json";

export const Post = ({ params }: { params: { slug: string } }) => {
  const post = posts.find((p) => p.slug === params.slug);

  if (!post) {
    return new Response("Not Found", { status: 404 });
  }

  const htmlBody = marked(post.body);
  const rawDescription = post.body.slice(0, 100);
  const escapedDescription = rawDescription
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");

  return (
    <>
      <title>{post.title}</title>
      <meta name="description" content={escapedDescription} />
      <h1>{post.title}</h1>
      <div dangerouslySetInnerHTML={{ __html: htmlBody }} />
    </>
  );
};

import posts from "../../data/posts.json";

export const Home = () => {
  return (
    <div>
      <h1>Blog Posts</h1>
      <ul>
        {posts.map((post) => (
          <li key={post.slug} style={{ border: "1px solid #ccc", margin: "10px", padding: "10px" }}>
            <h2>{post.title}</h2>
            <p>By {post.author}</p>
            <p>Published on {post.publishedDate}</p>
            <a href={`/posts/${post.slug}`}>Read more</a>
          </li>
        ))}
      </ul>
    </div>
  );
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { Post } from "@/app/pages/post";
import posts from "@/data/posts.json";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  route("/posts/:slug/raw", ({ params }) => {
    const post = posts.find(p => p.slug === params.slug);
    if (!post) return new Response("Not Found", { status: 404 });
    return new Response(post.body, {
      status: 200,
      headers: { "Content-Type": "text/plain" }
    });
  }),
  render(Document, [
    route("/", Home),
    route("/posts/:slug", Post),
  ]),
]);

